var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"휴우, 이제 슬슬 여기도 정리가 된 것 같은데?","JPN":"ふう、そろそろ片付いてきたんじゃない？","ENG":"Phew, I think we're close to being done here.","TWN":"呼，這裡也整理得差不多了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금쯤이면 버넷 요원도 성배에 다다랐을 겁니다.","JPN":"今頃はエージェント・バーネットも聖杯に辿り着いているはずです。","ENG":"Agent Burnett must have arrived at the Holy Grail's location by now.","TWN":"現在這時候，伯內特應該也快到聖杯了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러니 슬슬 당신의 패배를 인정하는 편이 좋을 겁니다. 제임스 고고학부장.","JPN":"そろそろあなたの負けを認めなさい、ジェームス考古学部長。","ENG":"So, it would be wise to admit your defeat, James.","TWN":"所以你最好還是乖乖認輸吧，詹姆斯考古學教授。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 성배를 지키고 있던 인원들에게 통신이 왔습니다.","JPN":"学部長！　聖杯を見張っていた者からの連絡です。","ENG":"Sir! We received a message from the members who were guarding the Holy Grail.","TWN":"院長！守護聖杯的人員發來了訊息。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"맥크레디 학회장님께서 패하고 성배가 기관에 넘어갔다고 합니다.","JPN":"マクレディー学会長が破れ、聖杯が機関の手に渡ったと。","ENG":"President MacCready lost, and the Institute now has the Holy Grail.","TWN":"麥克蕾蒂學會長失敗了，聖杯被機關帶走了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님! 결단을 내리셔야 합니다.","JPN":"学部長！　決断を下してください。","ENG":"Sir! You must make a decision.","TWN":"院長！你必須做出決斷。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 모든 건 신탁대로였다네.","JPN":"いや、すべては神託通りだった。","ENG":"No. This was all according to the prophecy.","TWN":"不，一切都與神喻一致。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"안나 맥크레디의 사념이 그저 성배를 지키는 <color=#ffd34c>파수꾼</color>에 지나지 않는다는 것도.","JPN":"アンナ・マクレディーの思念はただ聖杯を守る<color=#ffd34c>番人</color>にすぎないことも。","ENG":"That Anna MacCready's lingering will was nothing more than a <color=#ffd34c>guard</color> assigned to protect the Holy Grail.","TWN":"安娜·麥克蕾蒂的意念只是守護聖杯的<color=#ffd34c>守護者</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"너희 중, 가장 <color=#ffd34c>선한 자</color>가 성배에 다다르리라는 것도.","JPN":"君たちの中で最も<color=#ffd34c>善なる者</color>が聖杯に辿り着くだろうということも。","ENG":"And that the most <color=#ffd34c>righteous</color> among you all will reach the Holy Grail.","TWN":"而你們當中，最<color=#ffd34c>善良的人</color>將到達聖杯面前。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"가장 선한 자?","JPN":"最も善なる者？","ENG":"The most righteous?","TWN":"最善良的人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇네.","JPN":"そうだよ。","ENG":"Correct.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신탁에 따르면 파수꾼이 봉인 수단을 제거하고, 선한 자는 성배를 놓아줄 것이라 속삭이더군.","JPN":"神託によれば、番人は封印の手段を排除し、善なる者は聖杯を手放すと囁かれていた。","ENG":"The prophecy told that the guard will remove the seal and the good will release the Holy Grail.","TWN":"根據神喻，守護者將解除封印手段，最善良之人將解放聖杯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그리하면, 마침내 신적 존재가 탄생하게 되리라는 것도 말이야.","JPN":"そうすることによって、ついに神的存在の誕生に至るということも。","ENG":"That the godlike entity will finally be born.","TWN":"如此，神之存在終將誕生。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"으윽……! 이 느낌은……!","JPN":"うっ……！　この感覚は……！","ENG":"Ngh...! This feeling is...!","TWN":"呃……！這感覺……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아무래도 시작된 모양이군.","JPN":"どうやら始まったようだね。","ENG":"Seems like it has started.","TWN":"看來已經開始了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그럼 먼저 물러나겠네. 적당히 마무리를 부탁하지.","JPN":"では先に失礼しよう。適当に始末を頼む。","ENG":"I'll take my leave. I trust you with the rest.","TWN":"那我先告辭了，就拜託你們善後了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님? 학부장님……!?","JPN":"学部長？　学部長……！？","ENG":"Sir? Sir...?!","TWN":"院長？院長……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"어디가려는 거야, 학부장님!","JPN":"どこ行くんだよ、学部長！","ENG":"Where do you think you're going, Dean?!","TWN":"喂！你要去哪裡呀，院長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"총알 가져가!","JPN":"弾丸持ってきな！","ENG":"Take these bullets with you!","TWN":"再吃我幾顆子彈嘛！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……그만하세요, 추종자.","JPN":"……やめてください、取り巻き。","ENG":"...Stop, Follower.","TWN":"……別說了，追隨者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"으음? 왜 그래? 빨리 따라가야지.","JPN":"え？　どうした？　早く追いかけないと。","ENG":"Hmm? What is it? We gotta go after him.","TWN":"咦？怎麼了？得快點跟上啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 제임스 고고학부장의 추적은 여기까지입니다.","JPN":"いいえ、ジェームス考古学部長の追跡はここまでです。","ENG":"No, our pursuit of the Dean of Archeology ends here.","TWN":"不，詹姆斯考古學教授就追到這裡了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"방금, 이명이 들리기 시작한 뒤로부터…….","JPN":"先ほど耳鳴りが始まった瞬間……","ENG":"Just now, after I started hearing that high-pitched noise...","TWN":"剛才，耳鳴開始之後……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그자가 사라진 방향에서 숨이 막힐 정도의 고준위 침식파가 흘러나오고 있어요.","JPN":"彼が消えた方向から、息苦しいほどの高レベルの侵食波が流れ込んできています。","ENG":"A suffocatingly high-level Corruption ray has been flowing out from the direction he went.","TWN":"那個人消失的方向散發出了令人窒息的高危險級侵蝕波。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래? 난 아무렇지도 않은데?","JPN":"そう？　アタシはなんともないけど。","ENG":"Really? I feel fine.","TWN":"是嗎？我怎麼一點事都沒有？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 느낌…… 전에도 느껴 본 적 있습니다.","JPN":"こんな感覚……以前も経験したことがあります。","ENG":"I... have felt this way before.","TWN":"這種感覺……我以前也感受過。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니, 그때보다 수십배는 강해요.","JPN":"いえ、あの時より数十倍は強い。","ENG":"No, it is tenfold stronger than that.","TWN":"不，比那時候要強了數十倍。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"가면, 틀림없이 죽습니다.","JPN":"そこに行けば、間違いなく死にます。","ENG":"We will most definitely die if we go there.","TWN":"如果我們跟上去，必死無疑。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어쩌면…… 지금 그곳에 있는 버넷 요원은…….","JPN":"もしかすると……今そこにいるエージェント・バーネットは……","ENG":"Perhaps... Agent Burnett there might be...","TWN":"說不定……現在在那裡的伯內特……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……다들 들려?","JPN":"……皆、聞こえるか？","ENG":"...Can you hear me?","TWN":"……大家能聽見嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"버넷 요원! 성배는 어떻게 되었습니까?","JPN":"エージェント・バーネット！　聖杯はどうなりましたか！","ENG":"Agent Burnett! What happened to the Holy Grail?!","TWN":"伯內特！聖杯怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"성배의 봉인은…… 실패했어.","JPN":"聖杯の封印は……失敗した。","ENG":"I... failed to seal the Holy Grail.","TWN":"聖杯的封印……失敗了。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"곧 성배를 매개로…… 존재해서는 안 되는 존재가 이 세계에 나타날 거야.","JPN":"もうすぐ聖杯を媒介に……在ってはならない存在がこの世界に現れる。","ENG":"Soon... something that shouldn't exist is going to emerge into this world through the Holy Grail.","TWN":"以聖杯為媒介……這個世界即將會出現不該出現的存在。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 다들 함선으로 돌아가서 빨리 여길 뜨라고.","JPN":"だから皆艦船に戻って、早くここから離れろ。","ENG":"So get back to the ship and leave this place.","TWN":"所以大家趕緊回到艦船，離開這裡。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저희가 함선을 타고 여길 떠나면, 당신은 어쩔 작정이죠?","JPN":"私たちがここを離れたら、あなたはどうするつもりですか？","ENG":"If we take the ship and leave, what will you do?","TWN":"如果我們坐艦船離開這裡，那你怎麼辦？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"사태가 이 지경에 이른 건, 전부 나 때문이야.","JPN":"こんなことになったのは、全部俺のせいだ。","ENG":"It's all because of me that things ended up like this.","TWN":"事態發展到這個地步，全是因為我。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까 기관이 도착할 때까지 시간을 벌겠어.","JPN":"だから機関が来るまで、時間を稼ぐ。","ENG":"So I'll buy some time until the Institution arrives.","TWN":"所以我會爭取時間，直到機關到達為止。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잠깐……! 버넷 요원……!","JPN":"待ってください……！　エージェント・バーネット……！","ENG":"Wait...! Agent Burnett...!","TWN":"等一下……！伯內特……！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기관이 도착할 때까지 버티겠다고?","JPN":"機関が来るまで耐える？","ENG":"You think you can hold your ground until the Institution arrives?","TWN":"堅持到機關到達？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"우습군.","JPN":"笑わせてくれるな。","ENG":"How pitiful.","TWN":"可笑至極。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이곳은 시간이 매우 천천히 흐르는 초고심도의 이면 세계야.","JPN":"ここは時間の流れが非常に遅い、超高深度の裏世界だ。","ENG":"This is the hyperdepths of the Counterside, where time flows ever so slowly.","TWN":"這裡是時間流逝非常緩慢的超深度異界。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"현실에서 조금이라도 지체되었다면, 이곳에 도착하기까지 몇 시간…….","JPN":"現実で少しでも遅れると、ここに辿り着くには数時間……","ENG":"Even the tiniest delay in the Normalside would cause their arrival to take hours...","TWN":"如果在現世中稍有耽擱，到達這個地方就要幾個小時……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아니, 며칠이 걸릴지도 모르지.","JPN":"いや、数日後になるかもしれない。","ENG":"or maybe even days.","TWN":"不，說不定需要好幾天的時間。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기관이 얼마나 빨리 도착할 수 있을까?","JPN":"機関がいつここに来ると思う？","ENG":"How quickly will the Institution arrive?","TWN":"機關能多快來到這裡呢？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아무것도 남지 않은 네가…… 그때까지 버틸 수는 있을까?","JPN":"何もないお前に……それまで耐えることができると思うか？","ENG":"Will you be able to stand your ground until then...? With nothing to rely on?","TWN":"什麼都不剩下的你……能堅持到那個時候嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워…….","JPN":"うるせえ……","ENG":"Shut up...","TWN":"閉嘴……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"버틸 수 있느냐, 없느냐…… 그런 게 중요한 게 아니야.","JPN":"耐えられるか、耐えられないか……そんなことはどうでもいい。","ENG":"It's not important... whether I can stand my ground or not.","TWN":"能不能撐下去……不重要。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 자리에서 죽는 한이 있더라도, 난 도망치지 않겠어.","JPN":"たとえこの場で死ぬことになっても、俺は逃げない。","ENG":"I'm not running away, even if it means I die here on this spot.","TWN":"哪怕死在這裡，我也不會逃跑。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇지 않으면…… 그 사람도, 그 아이도 더는 마주할 면목이 없을 테니까.","JPN":"でないと……あの人にも、あの子にも合わせる顔がないんだ。","ENG":"Because if I run away here... I won't be able to face him, or the child.","TWN":"不然的話……無論是他，還是那個孩子，我都會無顏面對。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"마지막까지 허세인가.","JPN":"最後まで見栄を張るか。","ENG":"Bluffing, even in your last moments.","TWN":"難道到最後都還在虛張聲勢嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니께서 육신을 얻고 현현하기까지는…… 앞으로 시간이 조금 더 필요하시겠지.","JPN":"お母さんが受肉し顕現するまで……もう少し時間がかかるだろう。","ENG":"Mother will need... more time to gain a physical form and manifest herself.","TWN":"等待母親獲得肉身直到降臨……還需要一點時間。"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그럼, 잠시나마 이 결투를 즐겨보도록 할까, 로이 버넷?","JPN":"ではその間、戦いを楽しんでみるとするか。","ENG":"Then, shall we indulge ourselves in this battle for a moment, Roy Burnett?","TWN":"那麼，讓我們享受一下這場決鬥吧，羅伊？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CA_EVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};